package main

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"strings"
	"time"
)

type scores struct {
	X     int
	O     int
	Draws int
}

func clearScreen() {
	fmt.Print("\033[2J\033[H")
}

func renderBoard(b [9]string, sc scores, highlight []int, blink bool) {
	var sb strings.Builder

	sb.WriteString("\n")
	sb.WriteString(fmt.Sprintf("\033[37mScore: X: %d | O: %d | Draws: %d\033[0m\n\n", sc.X, sc.O, sc.Draws))

	for i := 0; i < 9; i++ {
		if i == 3 || i == 6 {
			sb.WriteString("----------\n")
		}
		if i%3 == 0 && i > 0 {
			sb.WriteString("\n")
		}

		val := b[i]
		isHighlight := false
		for _, h := range highlight {
			if h == i {
				isHighlight = true
				break
			}
		}

		switch val {
		case "X":
			if isHighlight && blink {
				sb.WriteString("\033[5m\033[31;1mX\033[0m")
			} else {
				sb.WriteString("\033[31;1mX\033[0m")
			}
		case "O":
			if isHighlight && blink {
				sb.WriteString("\033[5m\033[32;1mO\033[0m")
			} else {
				sb.WriteString("\033[32;1mO\033[0m")
			}
		default:
			sb.WriteString("\033[37m" + val + "\033[0m")
		}

		if i%3 != 2 {
			sb.WriteString(" | ")
		}
	}

	sb.WriteString("\n\n")
	fmt.Print(sb.String())
}

func playerX() int {
	for {
		fmt.Print("\033[31;1mPlayer X's turn. Enter a number (1-9): \033[0m")
		reader := bufio.NewReader(os.Stdin)
		input, _ := reader.ReadString('\n')
		input = strings.TrimSpace(input)

		n, err := strconv.Atoi(input)
		if err != nil || n < 1 || n > 9 {
			fmt.Println("Invalid input. Enter a number between 1 and 9.")
			continue
		}

		idx := n - 1
		if idx >= 0 && idx < 9 && input == string(idx+1+'0') {
			// already validated above
		}

		return idx
	}
}

func playerO() int {
	for {
		fmt.Print("\033[32;1mPlayer O's turn. Enter a number (1-9): \033[0m")
		reader := bufio.NewReader(os.Stdin)
		input, _ := reader.ReadString('\n')
		input = strings.TrimSpace(input)

		n, err := strconv.Atoi(input)
		if err != nil || n < 1 || n > 9 {
			fmt.Println("Invalid input. Enter a number between 1 and 9.")
			continue
		}

		return n - 1
	}
}

func getValidMoves(b [9]string) []int {
	var moves []int
	for i, v := range b {
		if v == "X" || v == "O" {
			continue
		}
		moves = append(moves, i)
	}
	return moves
}

func checkWinner(b [9]string) (int, []int) {
	lines := [][3]int{
		{0, 1, 2}, {3, 4, 5}, {6, 7, 8}, // rows
		{0, 3, 6}, {1, 4, 7}, {2, 5, 8}, // cols
		{0, 4, 8}, {2, 4, 6},             // diags
	}

	for _, line := range lines {
		if b[line[0]] != "" && b[line[0]] == b[line[1]] && b[line[1]] == b[line[2]] {
			player := 0
			if b[line[0]] == "X" {
				player = 1
			} else {
				player = 2
			}
			return player, line
		}
	}
	return 0, nil
}

func checkDraw(b [9]string) bool {
	for _, v := range b {
		if v == "X" || v == "O" {
			continue
		}
		return false
	}
	return true
}

func playGame(sc *scores) {
	var board [9]string
	for i := 0; i < 9; i++ {
		board[i] = strconv.Itoa(i + 1)
	}

	clearScreen()
	renderBoard(board, *sc, nil, false)

	for {
		// Player X's turn
		for {
			fmt.Print("\033[31;1mPlayer X's turn. Enter a number (1-9): \033[0m")
			reader := bufio.NewReader(os.Stdin)
			input, _ := reader.ReadString('\n')
			input = strings.TrimSpace(input)

			n, err := strconv.Atoi(input)
			if err != nil || n < 1 || n > 9 {
				fmt.Println("Invalid input. Enter a number between 1 and 9.")
				continue
			}

			idx := n - 1
			if board[idx] != "X" && board[idx] != "O" {
				board[idx] = "X"
				break
			}
			fmt.Println("Space already taken. Choose another.")
		}

		clearScreen()
		renderBoard(board, *sc, nil, false)

		winner, winCells := checkWinner(board)
		if winner == 1 {
			sc.X++
			time.Sleep(2 * time.Second)
			clearScreen()
			renderBoard(board, *sc, winCells, true)
			time.Sleep(2 * time.Second)
			fmt.Printf("\n\033[31;1mGame Over! X wins!\033[0m\n\n")
			return
		}

		if checkDraw(board) {
			sc.Draws++
			clearScreen()
			renderBoard(board, *sc, nil, false)
			fmt.Printf("\n\033[37mGame Over! It's a draw!\033[0m\n\n")
			return
		}

		// Player O's turn
		for {
			fmt.Print("\033[32;1mPlayer O's turn. Enter a number (1-9): \033[0m")
			reader := bufio.NewReader(os.Stdin)
			input, _ := reader.ReadString('\n')
			input = strings.TrimSpace(input)

			n, err := strconv.Atoi(input)
			if err != nil || n < 1 || n > 9 {
				fmt.Println("Invalid input. Enter a number between 1 and 9.")
				continue
			}

			idx := n - 1
			if board[idx] != "X" && board[idx] != "O" {
				board[idx] = "O"
				break
			}
			fmt.Println("Space already taken. Choose another.")
		}

		clearScreen()
		renderBoard(board, *sc, nil, false)

		winner, winCells = checkWinner(board)
		if winner == 2 {
			sc.O++
			time.Sleep(2 * time.Second)
			clearScreen()
			renderBoard(board, *sc, winCells, true)
			time.Sleep(2 * time.Second)
			fmt.Printf("\n\033[32;1mGame Over! O wins!\033[0m\n\n")
			return
		}

		if checkDraw(board) {
			sc.Draws++
			clearScreen()
			renderBoard(board, *sc, nil, false)
			fmt.Printf("\n\033[37mGame Over! It's a draw!\033[0m\n\n")
			return
		}
	}
}

func main() {
	var sc scores

	for {
		playGame(&sc)

		fmt.Print("Play again? (y/n): ")
		reader := bufio.NewReader(os.Stdin)
		input, _ := reader.ReadString('\n')
		input = strings.TrimSpace(strings.ToLower(input))

		if input != "y" {
			fmt.Println("Thanks for playing!")
			break
		}

		clearScreen()
	}
}
